app.get('/health', async (req, res) => {
  try {
    const r = await client.info();
    res.json({ ok: true, elasticsearch: { name: r.name, cluster_name: r.cluster_name, version: r.version?.number } });
  } catch (e) {
    res.status(503).json({ ok: false, error: 'elasticsearch_unavailable' });
  }
});

app.post('/search', async (req, res, next) => {
  try {
    const { index, body } = buildQueryDSL(req.body);
    const resp = await client.search({ index, ...body });
    res.json(resp);
  } catch (e) {
    next(e);
  }
});

app.post('/msearch', async (req, res, next) => {
  try {
    const payload = req.body;
    if (!isPlainObject(payload)) throw httpError(400, 'payload must be an object');
    const searches = toArray(payload.searches);
    if (!searches.length) throw httpError(400, 'searches must be a non-empty array');

    const body = [];
    for (const s of searches) {
      const { index, body: b } = buildQueryDSL(s);
      body.push({ index });
      body.push(b);
    }

    const resp = await client.msearch({ body });
    res.json(resp);
  } catch (e) {
    next(e);
  }
});

app.use((err, req, res, next) => {
  const status = err.status || 500;
  const out = {
    error: {
      message: err.message || 'internal_error',
      status,
      details: err.details,
    },
  };
  res.status(status).json(out);
});

